import React, { useState } from 'react';

const ITEMS = ["Deductible", "Premium", "Copay", "Out-of-Pocket Max", "HSA", "PPO vs HMO"];

const _PROMPT = `You are InsurePlain, a friendly, expert insurance assistant. Your goal is to take complex insurance terms, policy fine print, policy clauses, or jargon and explain them in completely plain English so anyone can understand them. Break down what it means, who it affects, and what someone needs to do next. Keep things highly readable using clear paragraphs or short bullet points where appropriate.`;

function App() {
  const [input, setInput] = useState('');
  const [output, setOutput] = useState('');
  const [loading, setLoading] = useState(false);

  const handleDecode = async (term) => {
    const searchTerm = term || input;
    if (!searchTerm.trim()) return;

    setLoading(true);
    setOutput('');

    try {
      const response = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': process.env.REACT_APP_ANTHROPIC_API_KEY,
          'anthropic-version': '2023-06-01',
          'dangerouslyAllowBrowser': 'true'
        },
        body: JSON.stringify({
          model: 'claude-3-5-sonnet-20241022',
          max_tokens: 1200,
          system: _PROMPT,
          messages: [
            { role: 'user', content: `Explain this insurance item plainly: ${searchTerm}` }
          ]
        })
      });

      if (!response.ok) {
        throw new Error(`API Error: ${response.status}`);
      }

      const data = await response.json();
      setOutput(data.content[0].text);
    } catch (error) {
      console.error(error);
      setOutput('Error connecting to the decoder engine. Please check your local server console or configuration.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app-container" style={{ fontFamily: 'sans-serif', padding: '40px', maxWidth: '600px', margin: '0 auto' }}>
      <header className="app-header">
        <h1>insureplain</h1>
        <p className="subtitle" style={{ color: '#666' }}>Insurance policies & fine print, finally explained.</p>
        <p className="description">
          Type any insurance term, policy clause, or acronym and get a plain-English breakdown — what it means, who it affects, and what to do next.
        </p>
        <div className="warning-box" style={{ background: '#fff3cd', padding: '15px', borderRadius: '5px', marginBottom: '20px' }}>
          ⚠️ For educational purposes only. InsurePlain does not provide financial, legal, or professional insurance advice. Always consult a licensed broker regarding your specific coverage.
        </div>
      </header>

      <main className="app-main">
        <div className="search-box" style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Enter an insurance code, clause, or term..."
            disabled={loading}
            style={{ flex: 1, padding: '10px', fontSize: '16px' }}
          />
          <button onClick={() => handleDecode()} disabled={loading} style={{ padding: '10px 20px', fontSize: '16px', cursor: 'pointer' }}>
            {loading ? 'Decoding...' : 'Decode'}
          </button>
        </div>

        <div className="quick-tags" style={{ marginBottom: '30px' }}>
          <span className="tags-label" style={{ marginRight: '10px' }}>Common:</span>
          {ITEMS.map((item) => (
            <button
              key={item}
              className="tag-btn"
              onClick={() => {
                setInput(item);
                handleDecode(item);
              }}
              disabled={loading}
              style={{ marginRight: '8px', padding: '5px 10px', cursor: 'pointer' }}
            >
              {item}
            </button>
          ))}
        </div>

        {output && (
          <div className="output-box" style={{ background: '#f8f9fa', padding: '20px', borderRadius: '5px', border: '1px solid #ddd' }}>
            <h3>Plain-English Breakdown:</h3>
            <div className="output-text" style={{ lineHeight: '1.6', whiteSpace: 'pre-wrap' }}>{output}</div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
